agent.inlineScript:
const fs = require('fs');
const input = JSON.parse(fs.readFileSync('/output/input.json', 'utf8'));
const report = input.steps?.['generate-report']?.result ?? {};
const articles = report.articles ?? input.steps?.['summarize-articles']?.result?.articles ?? [];
const topStories = report.topStories ?? [];
const meta = report.metadata ?? {};
const date = meta.reportDate ?? new Date().toISOString().slice(0, 10);

function esc(s) { return String(s ?? '').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;'); }

const catColors = { regulatory:'#dc2626', 'clinical-trial':'#2563eb', product:'#059669', partnership:'#7c3aed', financial:'#d97706', other:'#6b7280' };
function badge(cat) { const c = catColors[cat] ?? '#6b7280'; return `<span style="display:inline-block;font-size:11px;padding:1px 6px;border-radius:3px;background:${c}15;color:${c};border:1px solid ${c}30">${esc(cat)}</span>`; }
function importance(n) { const c = n >= 7 ? '#dc2626' : n >= 4 ? '#d97706' : '#6b7280'; return `<span style="font-size:11px;font-weight:600;color:${c}">${n}/10</span>`; }

let execSummary = '';
for (const ts of topStories.slice(0, 3)) {
  const a = articles.find(x => x.headline === ts.headline);
  execSummary += `<tr><td style="padding:6px 0;border-bottom:1px solid #f0f0f0"><strong>${esc(ts.headline)}</strong><br><span style="font-size:12px;color:#666">${esc(ts.company ?? 'Industry')} · ${importance(ts.importance)}</span>${a ? `<br><span style="font-size:12px;color:#888">${esc(a.summary ?? a.snippet ?? '')}</span>` : ''}</td></tr>`;
}

const byCompany = {};
for (const a of articles) {
  const key = a.company ?? '_industry';
  (byCompany[key] ??= []).push(a);
}

let sections = '';
for (const [company, arts] of Object.entries(byCompany)) {
  const label = company === '_industry' ? 'Industry-Wide' : company;
  sections += `<h2 style="font-size:16px;color:#1a1a1a;border-bottom:1px solid #e5e5e5;padding-bottom:4px;margin:24px 0 10px">${esc(label)}</h2>`;
  for (const a of arts.sort((x,y) => (y.importance??0)-(x.importance??0))) {
    sections += `<div style="margin:0 0 16px"><div>${badge(a.category)} ${importance(a.importance ?? 0)} <strong>${esc(a.headline)}</strong></div><p style="margin:4px 0;font-size:13px;color:#444">${esc(a.summary ?? a.snippet ?? '')}</p><div style="font-size:11px;color:#999">${a.sourceUrl ? `<a href="${esc(a.sourceUrl)}" style="color:#2563eb;text-decoration:none">${esc(a.source)}</a>` : esc(a.source)} · ${esc(a.date)}</div></div>`;
  }
}

const html = `<!DOCTYPE html><html><head><meta charset="utf-8"></head><body style="margin:0;padding:0;background:#f5f5f5;font-family:-apple-system,Segoe UI,Roboto,sans-serif"><div style="max-width:640px;margin:20px auto;background:#fff;border:1px solid #e0e0e0;border-radius:8px;overflow:hidden"><div style="background:#0f172a;color:#fff;padding:16px 24px"><div style="font-size:11px;text-transform:uppercase;letter-spacing:1.5px;opacity:0.6">Daily Briefing</div><div style="font-size:20px;font-weight:700;margin-top:2px">Pharma Media Report — ${esc(date)}</div></div><div style="padding:24px;font-size:14px;line-height:1.6;color:#333"><h2 style="font-size:16px;color:#1a1a1a;margin:0 0 10px">Executive Summary</h2><table style="width:100%;border-collapse:collapse">${execSummary}</table>${sections}</div><div style="background:#f9fafb;border-top:1px solid #e5e5e5;padding:12px 24px;font-size:11px;color:#999;text-align:center">Monitoring: Pfizer, Novartis, Roche, AstraZeneca, Solid Biosciences, Novo Nordisk<br>Sources: FDA, EMA, Fierce Pharma, Endpoints News, Reuters<br><br>Generated by Mediforce · Media Monitoring Workflow</div></div></body></html>`;

fs.writeFileSync('/output/result.json', JSON.stringify({ html, subject: `Pharma Media Report — ${date}`, articleCount: articles.length }));
